// Re-serves the OpenAPI spec generated by
// `clojure -M:ee:doc api-documentation` (docs/api.json) under the docs base
// path, so /docs/<version>/api.json is fetchable by the Scalar viewer.
import type { APIRoute } from "astro";
import apiSpec from "../../../docs/api.json";

export const prerender = true;

export const GET: APIRoute = () =>
  new Response(JSON.stringify(apiSpec), {
    headers: { "Content-Type": "application/json" },
  });
